    """Find the current plan and PR values for a node in the roadmap body.

    Returns:
        (previous_plan, previous_pr, found)
    """
    phases, _ = parse_roadmap(body)
    for phase in phases:
        for step in phase.nodes:
            if step.id == node_id:
                return step.plan, step.pr, True
    return None, None, False

