    nodes = parse_roadmap_frontmatter(roadmap_block.body)
    if nodes is None:
        click.echo(
            json.dumps(
                {
                    "success": False,
                    "error": "parse_failed",
                    "message": f"Failed to parse roadmap frontmatter for issue #{issue_number}",
